export const ServiceType = {
    PlanEscort: 'plan_escort',
    PlanShuttle: 'plan_shuttle',
    PlanCharter: 'plan_charter',
    PlanDragonMassage: 'plan_dragon_massage',
    PlanTutor: 'plan_tutor',
} as const

export type ServiceType = (typeof ServiceType)[keyof typeof ServiceType]

export const ServiceTypeLabel: Record<ServiceType, string> = {
    [ServiceType.PlanEscort]: '奧黛導遊',
    [ServiceType.PlanShuttle]: '機場接送',
    [ServiceType.PlanCharter]: '包車服務',
    [ServiceType.PlanDragonMassage]: '龍筋按摩',
    [ServiceType.PlanTutor]: '越語家教',
}

export const DiscountType = {
    Fixed: 'fixed',
    Percentage: 'percentage',
} as const

export type DiscountType = (typeof DiscountType)[keyof typeof DiscountType]

export const CommissionType = {
    Fixed: 'fixed',
    Percentage: 'percentage',
} as const

export type CommissionType = (typeof CommissionType)[keyof typeof CommissionType]

export type ServiceDetail = {
    id: number
    couponId: number
    serviceType: ServiceType
    discountType: DiscountType
    discountValue: number
    commissionType: CommissionType
    commissionValue: number
    createdAt: string
    updatedAt: string
}

export type Coupon = {
    id: number
    promoterId: number
    code: string
    startTimestamp: string
    endTimestamp: string
    createdAt: string
    updatedAt: string
    // joined
    promoterName?: string
    serviceDetails?: ServiceDetail[]
}

export type CreateServiceDetailInput = {
    serviceType: ServiceType
    discountType: DiscountType
    discountValue: number
    commissionType: CommissionType
    commissionValue: number
}

export type CreateCouponRequest = {
    promoterId: number
    code: string
    startTimestamp: string
    endTimestamp: string
    serviceDetails: CreateServiceDetailInput[]
}

export type UpdateCouponRequest = {
    id: number
    code?: string
    startTimestamp?: string
    endTimestamp?: string
}
