import { Ref, ref, watch } from 'vue'
import { Coupon, ServiceDetail, CreateCouponRequest, UpdateCouponRequest } from '../types'
import { watchIgnorable } from '@vueuse/core'
import api from '../../../services/api'

export type Pagination = {
    page: number
    perPage: number
    total: number
}

export type Filters = {
    promoterId: number | ''
    serviceType: string
}

const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })
const makeFiltersRef = () => ref<Partial<Filters>>({ promoterId: '', serviceType: '' })

export type PromoterOption = {
    id: number
    userId: number
    status: 'active' | 'inactive'
    userName?: string
}

export const useCoupons = (options?: { pagination?: Ref<Pagination>; filters?: Ref<Partial<Filters>> }) => {
    const isLoading = ref(false)
    const coupons = ref<Coupon[]>([])
    const promoters = ref<PromoterOption[]>([])
    const users = ref<{ id: number; firstName?: string; lastName?: string; nickname?: string; email?: string }[]>([])

    const { filters = makeFiltersRef(), pagination = makePaginationRef() } = options || {}

    const fetchUsers = async () => {
        try {
            const { data } = await api.axiosInstance.get('/user')
            users.value = data.data
        } catch (error) {
            console.error('Error fetching users:', error)
        }
    }

    const fetchPromoters = async () => {
        try {
            const { data } = await api.axiosInstance.get('/affiliate/promoter', { params: { limit: 100 } })
            const rawPromoters = data.data as PromoterOption[]
            promoters.value = rawPromoters.map((p) => ({
                ...p,
                userName: getUserDisplayName(p.userId),
            }))
        } catch (error) {
            console.error('Error fetching promoters:', error)
        }
    }

    const getUserDisplayName = (userId: number): string => {
        const user = users.value.find((u) => u.id === userId)
        if (!user) return `User #${userId}`
        if (user.nickname) return user.nickname
        if (user.firstName || user.lastName) return `${user.firstName || ''} ${user.lastName || ''}`.trim()
        return user.email || `User #${userId}`
    }

    const getPromoterName = (promoterId: number): string => {
        const promoter = promoters.value.find((p) => p.id === promoterId)
        return promoter?.userName || `Promoter #${promoterId}`
    }

    const fetchServiceDetails = async (couponId: number): Promise<ServiceDetail[]> => {
        try {
            const { data } = await api.axiosInstance.get(`/affiliate/coupon/${couponId}/service-details`, {
                params: { limit: 100 },
            })
            return data.data as ServiceDetail[]
        } catch (error) {
            console.error('Error fetching service details:', error)
            return []
        }
    }

    const fetch = async () => {
        isLoading.value = true
        try {
            const params: Record<string, any> = {
                page: pagination.value.page,
                limit: pagination.value.perPage,
            }
            if (filters.value.promoterId) {
                params.promoterId = filters.value.promoterId
            }

            const { data } = await api.axiosInstance.get('/affiliate/coupon', { params })
            const rawCoupons = data.data as Coupon[]

            // fetch service details for each coupon
            const couponsWithDetails = await Promise.all(
                rawCoupons.map(async (c) => {
                    const serviceDetails = await fetchServiceDetails(c.id)
                    return {
                        ...c,
                        promoterName: getPromoterName(c.promoterId),
                        serviceDetails,
                    }
                }),
            )

            // client-side filter by serviceType
            if (filters.value.serviceType) {
                coupons.value = couponsWithDetails.filter(
                    (c) => c.serviceDetails?.some((sd) => sd.serviceType === filters.value.serviceType),
                )
            } else {
                coupons.value = couponsWithDetails
            }

            ignoreUpdates(() => {
                pagination.value = {
                    page: data.page || pagination.value.page,
                    perPage: data.limit || pagination.value.perPage,
                    total: data.total || 0,
                }
            })
        } catch (error) {
            console.error('Error fetching coupons:', error)
        } finally {
            isLoading.value = false
        }
    }

    const { ignoreUpdates } = watchIgnorable([pagination], fetch, { deep: true })

    watch(
        filters,
        () => {
            pagination.value.page = 1
            fetch()
        },
        { deep: true },
    )

    const init = async () => {
        await fetchUsers()
        await fetchPromoters()
        await fetch()
    }

    init()

    return {
        isLoading,
        filters,
        pagination,
        coupons,
        promoters,
        fetch,
        getPromoterName,

        async add(request: CreateCouponRequest) {
            isLoading.value = true
            try {
                await api.axiosInstance.post('/affiliate/coupon', request)
                await fetch()
            } catch (error) {
                console.error('Error adding coupon:', error)
                throw error
            } finally {
                isLoading.value = false
            }
        },

        async update(request: UpdateCouponRequest) {
            isLoading.value = true
            try {
                const { id, ...body } = request
                await api.axiosInstance.patch(`/affiliate/coupon/${id}`, body)
                await fetch()
            } catch (error) {
                console.error('Error updating coupon:', error)
                throw error
            } finally {
                isLoading.value = false
            }
        },

        async remove(couponId: number) {
            isLoading.value = true
            try {
                await api.axiosInstance.delete(`/affiliate/coupon/${couponId}`)
                await fetch()
            } catch (error) {
                console.error('Error deleting coupon:', error)
                throw error
            } finally {
                isLoading.value = false
            }
        },

        async getCouponDetail(couponId: number): Promise<Coupon | null> {
            try {
                const { data } = await api.axiosInstance.get(`/affiliate/coupon/${couponId}`)
                const coupon = data.data as Coupon
                const serviceDetails = await fetchServiceDetails(couponId)
                return {
                    ...coupon,
                    promoterName: getPromoterName(coupon.promoterId),
                    serviceDetails,
                }
            } catch (error) {
                console.error('Error fetching coupon detail:', error)
                return null
            }
        },
    }
}
